import{_ as t,o as d,c as o,a2 as a}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"驱散系统","description":"","frontmatter":{},"headers":[],"relativePath":"guide/effects-dispel.md","filePath":"guide/effects-dispel.md","lastUpdated":1781102744000}'),c={name:"guide/effects-dispel.md"};function r(l,e,s,i,n,p){return d(),o("div",null,[...e[0]||(e[0]=[a(`<h1 id="驱散系统" tabindex="-1">驱散系统 <a class="header-anchor" href="#驱散系统" aria-label="Permalink to &quot;驱散系统&quot;">​</a></h1><h2 id="驱散性类型-dispeltype" tabindex="-1">驱散性类型 (DispelType) <a class="header-anchor" href="#驱散性类型-dispeltype" aria-label="Permalink to &quot;驱散性类型 (DispelType)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>枚举值</th><th>中文名</th><th>能力</th></tr></thead><tbody><tr><td><code>None</code></td><td>无驱散</td><td>默认，不能驱散其他特效</td></tr><tr><td><code>Weak</code></td><td>弱驱散</td><td>消除可弱驱散的特效</td></tr><tr><td><code>DurativeWeak</code></td><td>持续性弱驱散</td><td>持续对弱驱散目标生效</td></tr><tr><td><code>TemporaryWeak</code></td><td>临时弱驱散</td><td>暂时使弱驱散可驱的特效无效化</td></tr><tr><td><code>Strong</code></td><td>强驱散</td><td>消除需强驱散和可弱驱散的特效</td></tr><tr><td><code>DurativeStrong</code></td><td>持续性强驱散</td><td>持续对强驱散目标生效</td></tr><tr><td><code>TemporaryStrong</code></td><td>临时强驱散</td><td>暂时使所有可驱散特效无效化</td></tr><tr><td><code>Special</code></td><td>特殊驱散</td><td>只对特定特效有效</td></tr></tbody></table><h2 id="被驱散性预设-dispelledtype" tabindex="-1">被驱散性预设 (DispelledType) <a class="header-anchor" href="#被驱散性预设-dispelledtype" aria-label="Permalink to &quot;被驱散性预设 (DispelledType)&quot;">​</a></h2><p>由 <code>SkillSet.GetDispelledTypeByEffectType()</code> 自动判定：</p><table tabindex="0"><thead><tr><th>特效类型</th><th>被驱散性</th><th>说明</th></tr></thead><tbody><tr><td><code>None</code>, <code>Item</code>, <code>Knockback</code>, <code>Unselectable</code>, <code>Doom</code></td><td><code>CannotBeDispelled</code></td><td>不可驱散</td></tr><tr><td><code>Stun</code>, <code>Freeze</code>, <code>Silence</code>, <code>Root</code>, <code>Fear</code>, <code>Sleep</code>, <code>Knockdown</code>, <code>Taunt</code>, <code>Invulnerable</code>, <code>Charm</code>, <code>Disarm</code>, <code>Confusion</code>, <code>Petrify</code>, <code>SilenceMagic</code>, <code>Banish</code></td><td><code>Strong</code></td><td>需强驱散</td></tr><tr><td>所有其他类型</td><td><code>Weak</code></td><td>可弱驱散</td></tr></tbody></table><h2 id="驱散逻辑" tabindex="-1">驱散逻辑 <a class="header-anchor" href="#驱散逻辑" aria-label="Permalink to &quot;驱散逻辑&quot;">​</a></h2><p>在 <code>Effect.cs</code> 中的驱散实现：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>强驱散 → 能消除 DispelledType.Weak + DispelledType.Strong</span></span>
<span class="line"><span>弱驱散 → 只能消除 DispelledType.Weak（且有限制：部分强控制无法被弱驱散消除）</span></span>
<span class="line"><span>特殊驱散 → 能消除 DispelledType.Special（由具体特效决定）</span></span></code></pre></div><h2 id="驱散目标策略" tabindex="-1">驱散目标策略 <a class="header-anchor" href="#驱散目标策略" aria-label="Permalink to &quot;驱散目标策略&quot;">​</a></h2><ul><li><strong>对敌方施加强驱散</strong> → 移除所有 BUFF（<code>IsDebuff = false</code> 且可驱散的）</li><li><strong>对友方施加强驱散</strong> → 移除所有 DEBUFF + 控制状态（<code>IsDebuff = true</code> 且可驱散的），非吟唱态时恢复常态</li><li><strong>对敌方施加弱驱散</strong> → 移除可弱驱散的 BUFF</li><li><strong>对友方施加弱驱散</strong> → 移除除完全行动不能/行动受限/战斗不能外的控制效果 + 所有软控制</li></ul>`,11)])])}const f=t(c,[["render",r]]);export{u as __pageData,f as default};
